#include <bits/stdc++.h>
using namespace std;
int n,m,ans=300001,a[3003],sum[3003];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        sum[i]=sum[i-1]+a[i];
        if(i>=m)ans=min(ans,sum[i]-sum[i-m]);
    }
    if(m==0){
        cout<<0;
        return 0;
    }
    cout<<ans;
    return 0;
}
